// Verify Stripe webhook signature and extract checkout data
const crypto = require('crypto');

const payload = $input.first().json.body;
const sig = $input.first().json.headers['stripe-signature'];
const secret = $env.STRIPE_WEBHOOK_SECRET;

// Verify signature (Stripe webhook security)
if (!sig || !secret) {
  throw new Error('Stripe webhook signature or secret missing — rejecting request');
}

const elements = sig.split(',');
const signatureMap = {};
elements.forEach(el => {
  const [key, value] = el.split('=');
  signatureMap[key] = value;
});
const timestamp = signatureMap['t'];
const receivedSig = signatureMap['v1'];

if (!timestamp || !receivedSig) {
  throw new Error('Stripe webhook signature malformed — missing timestamp or v1 signature');
}

// Reject requests with timestamps older than 5 minutes to prevent replay attacks
const currentTime = Math.floor(Date.now() / 1000);
if (Math.abs(currentTime - parseInt(timestamp, 10)) > 300) {
  throw new Error('Stripe webhook signature timestamp too old — possible replay attack');
}

const signedPayload = `${timestamp}.${JSON.stringify(payload)}`;
const expectedSig = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');

if (expectedSig !== receivedSig) {
  throw new Error('Stripe webhook signature verification failed — rejecting request');
}

// Only process checkout.session.completed events
if (payload.type !== 'checkout.session.completed') {
  return [{ json: { skip: true, reason: 'Not a checkout completion event' } }];
}

const session = payload.data.object;
const metadata = session.metadata || {};

// Extract purchase details from Stripe metadata
// SeedLink sets these when creating the checkout session:
// - modules: comma-separated list (e.g., "content,seo")
// - tier: basic|standard|premium
// - client_email: customer email
// - client_name: customer name
const clientData = {
  skip: false,
  event_type: payload.type,
  stripe_session_id: session.id,
  stripe_customer_id: session.customer,
  client_email: session.customer_email || metadata.client_email || '',
  client_name: metadata.client_name || session.customer_details?.name || '',
  modules: (metadata.modules || 'content').split(',').map(m => m.trim()),
  tier: metadata.tier || 'standard',
  amount_paid: session.amount_total / 100, // cents to dollars
  currency: session.currency || 'usd',
  payment_status: session.payment_status,
  purchased_at: new Date().toISOString(),

  // Calculate VV payout (75%) — updated per Mar 9 call
  vv_payout: Math.round((session.amount_total / 100) * 0.75 * 100) / 100,
  seedlink_commission: Math.round((session.amount_total / 100) * 0.25 * 100) / 100,

  // Generate client ID for multi-tenant tracking
  client_id: 'client_' + (metadata.client_name || 'unknown').toLowerCase().replace(/[^a-z0-9]/g, '_') + '_' + Date.now().toString(36)
};

return [{ json: clientData }];

