// Parse and validate the onboarding questionnaire submission
// This webhook receives data from Typeform/Google Form via Zapier/Make
// or from a custom form on seedlink.app

const body = $input.first().json.body;

const questionnaire = {
  // Identifiers
  client_id: body.client_id || '',
  client_email: body.client_email || '',

  // Section 1: Business
  brand_name: body.company_name || body.brand_name || '',
  website_url: body.website_url || '',
  brand_description: body.company_description || body.brand_description || '',
  target_audience: body.target_audience || body.icp || '',

  // Section 2: Voice
  has_existing_content: body.has_existing_content || false,
  content_samples: body.content_samples || [], // Array of URLs
  voice_preferences: body.voice_preferences || null, // Voice Builder A/B pairs
  reference_voices: body.reference_voices || '', // Free text
  closest_archetype: body.closest_archetype || '', // Dropdown selection
  quick_fire: body.quick_fire || null, // Object with 5 answers
  voice_recording_url: body.voice_recording_url || '', // Premium only
  words_to_use: body.words_to_use || '',
  words_to_avoid: body.words_to_avoid || '',
  voice_style_dropdown: body.voice_style || '', // Professional, Casual, etc.
  person_preference: body.person_preference || 'first', // first or company
  smart_vs_approachable: body.smart_vs_approachable || 'approachable',

  // Section 3: Content Strategy
  content_pillars: body.content_pillars || body.content_themes || '',
  target_keywords: body.target_keywords || '',
  cms_platform: body.cms_platform || 'wordpress',
  posts_per_month: body.posts_per_month || 4,

  // Section 4: Outreach
  linkedin_profiles: body.linkedin_profiles || '',
  has_prospai: body.has_prospai || false,
  crm_platform: body.crm_platform || 'none',
  calendly_url: body.calendly_url || '',

  // Section 5: Platforms
  social_platforms: body.social_platforms || 'linkedin,twitter',
  has_buffer: body.has_buffer || false,
  has_anthropic_key: body.has_anthropic_key || false,
  notification_channel: body.notification_channel || 'slack',
  slack_webhook: body.slack_webhook || '',

  // Modules purchased (passed through from Stripe)
  modules: body.modules || [],
  tier: body.tier || 'standard',

  // Metadata
  submitted_at: new Date().toISOString()
};

// Validate required fields
const missing = [];
if (!questionnaire.client_id) missing.push('client_id');
if (!questionnaire.brand_name) missing.push('company_name');
if (!questionnaire.client_email) missing.push('client_email');
if (!questionnaire.brand_description) missing.push('company_description');

questionnaire.validation_errors = missing;
questionnaire.is_valid = missing.length === 0;

return [{ json: questionnaire }];

// Create the client's Google Sheets workbook by cloning the template
// This uses the Google Drive API to copy the template spreadsheet
// and then renames it for the client

const questionnaire = $input.first().json;

// Store questionnaire data for downstream nodes
const clientConfig = {
  ...questionnaire,

  // Settings tab values (will be written to the new sheet)
  settings: {
    brand_name: questionnaire.brand_name,
    brand_description: questionnaire.brand_description,
    voice_style: 'See Voice Profile tab',
    content_pillars: questionnaire.content_pillars,
    cta_products: questionnaire.brand_name + ' marketplace, ' + questionnaire.brand_name + ' resources',
    blog_platform: questionnaire.cms_platform,
    linkedin_accounts: questionnaire.linkedin_profiles,
    target_audience: questionnaire.target_audience,
    ai_model: 'claude-sonnet-4-20250514',
    max_tokens_blog: '4096',
    max_tokens_social: '1024',
    max_tokens_meta: '512'
  },

  // Environment variables this client needs
  env_vars: {
    client_id: questionnaire.client_id,
    sheet_id: '', // Will be set after cloning
    blog_url: questionnaire.website_url,
    slack_webhook: questionnaire.slack_webhook || '',
    cms_platform: questionnaire.cms_platform
  }
};

return [{ json: clientConfig }];

// Capture the new sheet ID from the Drive copy response
const cloneResponse = $input.first().json;
const previousData = $('Code: Build Client Config').first().json;

const result = {
  ...previousData,
  new_sheet_id: cloneResponse.id,
  new_sheet_url: 'https://docs.google.com/spreadsheets/d/' + cloneResponse.id
};

// Update env_vars with the new sheet ID
result.env_vars.sheet_id = cloneResponse.id;

return [{ json: result }];

// Build batch update payload for all Settings tab rows
// This writes all client config values to the Settings tab in one operation
const data = $input.first().json;
const settings = data.settings;

const settingsRows = [
  { key: 'brand_name', value: settings.brand_name },
  { key: 'brand_description', value: settings.brand_description },
  { key: 'voice_style', value: settings.voice_style },
  { key: 'content_pillars', value: settings.content_pillars },
  { key: 'cta_products', value: settings.cta_products },
  { key: 'blog_platform', value: settings.blog_platform },
  { key: 'linkedin_accounts', value: settings.linkedin_accounts },
  { key: 'target_audience', value: settings.target_audience },
  { key: 'ai_model', value: settings.ai_model },
  { key: 'max_tokens_blog', value: settings.max_tokens_blog },
  { key: 'max_tokens_social', value: settings.max_tokens_social },
  { key: 'max_tokens_meta', value: settings.max_tokens_meta }
];

// Output each row as a separate item for batch processing
return settingsRows.map(row => ({ json: { ...data, setting_key: row.key, setting_value: row.value } }));

