// Check which clients' monitoring periods have ended
const clients = $input.all();
const today = new Date();
const results = [];

for (const client of clients) {
  const monitorEnd = new Date(client.json.monitoring_end);
  if (today >= monitorEnd) {
    results.push({
      json: {
        ...client.json,
        action: 'monitoring_complete',
        days_past_monitoring: Math.floor((today - monitorEnd) / (1000 * 60 * 60 * 24))
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { action: 'none', message: 'No monitoring periods ending this week' } }];
}

return results;

